<!doctype html><html><head><meta charset="utf-8"><title>Sales Target Report</title><style>body{font-family:Arial,sans-serif;color:#172033;padding:24px}h1{margin-bottom:4px}small{color:#667085}table{width:100%;border-collapse:collapse;margin-top:24px}th,td{border:1px solid #d9deea;padding:8px;text-align:left;font-size:12px}th{background:#eef2ff}@media print{.no-print{display:none}}</style></head><body><div class="no-print"><button onclick="window.print()">Download / Save PDF</button></div><h1>Sales Target Report</h1><small>Generated {{ now()->format('d M Y h:i A') }}</small><table><thead><tr><th>Party</th><th>Product Category</th><th>Period</th><th>Target Type</th><th>Target</th><th>Actual</th><th>Achievement</th><th>Amount</th><th>Quantity</th></tr></thead><tbody>@foreach($rows as $row)<tr><td>{{ $row['party'] }}</td><td>{{ $row['category'] }}</td><td>{{ $row['period'] }} ({{ $row['starts_on'] }} - {{ $row['ends_on'] }})</td><td>{{ $row['target_type'] }}</td><td>{{ number_format($row['target'],2) }}</td><td>{{ number_format($row['actual'],2) }}</td><td>{{ number_format($row['achievement'],1) }}%</td><td>Rs {{ number_format($row['actual_amount'],2) }}</td><td>{{ number_format($row['actual_quantity'],2) }}</td></tr>@endforeach</tbody></table><script>window.onload=()=>window.print()</script></body></html>
